kubectl exec -n mongodb mongodb-replica-1 -- mongosh --quiet "mongodb://admin-user:admin123password@localhost:27017/admin" --eval '
  print("=== Replica Set Status ===");
  rs.status().members.forEach(m => print(m.name, m.stateStr, "health=" + m.health));
  print("");
  print("=== FCV ===");
  printjson(db.adminCommand({getParameter:1, featureCompatibilityVersion:1}).featureCompatibilityVersion);
  print("");
  print("=== MongoDB Version (this node) ===");
  print(db.version());
  print("");
  print("=== Existing Data Check ===");
  printjson(db.getSiblingDB("testdb").data.find({},{_id:0}).toArray());
' 2>&1 | grep -v Browserslist | grep -v "npx " | grep -v "Why you" | grep -v "https://"
